internal final class ETGGMCControllerNew extends SrsReportRunController
{
}

Method.Source:
public static ETGGMCControllerNew construct()
{
    return new ETGGMCControllerNew();
}

public static void main(Args _args)
{
    ETGGMCControllerNew controller       = new ETGGMCControllerNew();
    ETGCanadaParameters canadaParameters = ETGCanadaParameters::find();

    if (canadaParameters.ETGSalesIdOnGMReport)
    {
        controller.parmReportName(ssrsReportStr(ETGGMCReportNew, ReportNew));
    }
    else
    {
        controller.parmReportName(ssrsReportStr(ETGGMCReportNew, Report));
    }

    controller.parmArgs(_args);
    controller.parmDialogCaption("@ETG_ENG_Labels:GMRReport");
    controller.startOperation();
}
